const items = $input.all();
const results = [];

for (const item of items) {
  const binaryKey = Object.keys(item.binary || {})[0];

  if (!binaryKey) {
    throw new Error('No binary data found.');
  }

  const binaryData = item.binary[binaryKey];

  results.push({
    json: {
      source_hash: binaryData.fileSize + '_' + Date.now(),
      source_file_name: binaryData.fileName || 'unknown.csv',
      _binaryKey: binaryKey
    },
    binary: item.binary
  });
}

return results;

const items = $input.all();
const results = [];

const sourceHash = $('Generate SHA-256 Hash').first().json.source_hash;
const sourceFileName = $('Generate SHA-256 Hash').first().json.source_file_name;

for (const item of items) {
  const row = { ...item.json };
  const errors = [];

  if (!row.invoice_number || String(row.invoice_number).trim() === '') errors.push('Missing invoice_number');
  if (!row.supplier_number || String(row.supplier_number).trim() === '') errors.push('Missing supplier_number');
  if (!row.supplier_name || String(row.supplier_name).trim() === '') errors.push('Missing supplier_name');
  if (!row.department || String(row.department).trim() === '') errors.push('Missing department');
  if (!row.invoice_date || String(row.invoice_date).trim() === '') errors.push('Missing invoice_date');
  if (row.amount_excl === undefined || row.amount_excl === null || row.amount_excl === '') errors.push('Missing amount_excl');

  const amount_excl_vat = parseFloat(row.amount_excl);
  const vat_rate = row.vat_rate ? parseFloat(row.vat_rate) : 15.0;
  let vat = row.vat !== undefined && row.vat !== '' && row.vat !== null
    ? parseFloat(row.vat)
    : parseFloat((amount_excl_vat * vat_rate / 100).toFixed(2));
  let amount_incl_vat = parseFloat((amount_excl_vat + vat).toFixed(2));

  if (errors.length === 0) {
    const diff = Math.abs((amount_excl_vat + vat) - amount_incl_vat);
    if (diff > 0.01) {
      errors.push('VAT math mismatch');
    }
  }

  // Handle Excel serial date number or normal date string
  let invoiceDateStr = String(row.invoice_date).trim();
  let invoiceDate;

  if (!isNaN(invoiceDateStr) && Number(invoiceDateStr) > 40000) {
    const excelEpoch = new Date(1899, 11, 30);
    invoiceDate = new Date(excelEpoch.getTime() + Number(invoiceDateStr) * 86400000);
    invoiceDateStr = invoiceDate.toISOString().split('T')[0];
  } else {
    invoiceDate = new Date(invoiceDateStr);
  }

  if (isNaN(invoiceDate.getTime())) {
    errors.push('Invalid invoice_date: ' + invoiceDateStr);
  } else {
    const today = new Date();
    today.setHours(23, 59, 59, 999);
    if (invoiceDate > today) {
      errors.push('invoice_date is in the future: ' + invoiceDateStr);
    }
  }

  const isValid = errors.length === 0;

  results.push({
    json: {
      invoice_number: String(row.invoice_number || '').trim(),
      supplier_number: String(row.supplier_number || '').trim(),
      supplier_name: String(row.supplier_name || '').trim(),
      department: String(row.department || '').trim(),
      amount_excl_vat: isNaN(amount_excl_vat) ? null : amount_excl_vat,
      vat: isNaN(vat) ? null : vat,
      amount_incl_vat: isNaN(amount_incl_vat) ? null : amount_incl_vat,
      invoice_date: invoiceDateStr,
      source_file_name: sourceFileName,
      source_hash: sourceHash,
      valid: isValid,
      validation_notes: errors.join('; ') || null
    }
  });
}

return results;

// Mark this record as duplicate — do not insert
const item = $input.first();
return [{
  json: {
    ...item.json,
    status: 'duplicate',
    validation_notes: 'Duplicate: (supplier_number, invoice_number) already exists in supplier_invoices'
  }
}];

// Mark failed validation records with status='failed'
const item = $input.first();
return [{
  json: {
    ...item.json,
    status: 'failed'
  }
}];

// Since INSERT uses ON CONFLICT DO NOTHING, we count based on 
// what was processed by the validate node
const allItems = $input.all();

// Get counts from the validate node output via the route
let inserted = 0;
let duplicates = 0;
let failed = 0;
const errors = [];

for (const item of allItems) {
  // Check what came through
  const s = item.json.status;
  const success = item.json.success;

  if (s === 'failed') {
    failed++;
    errors.push({
      invoice_number: item.json.invoice_number || 'N/A',
      supplier_number: item.json.supplier_number || 'N/A',
      reason: item.json.validation_notes || 'Validation failed'
    });
  } else if (s === 'duplicate') {
    duplicates++;
  } else if (success === true || s === 'inserted') {
    inserted++;
  }
}

// If nothing counted, check if success came through
if (inserted === 0 && duplicates === 0 && failed === 0) {
  inserted = allItems.filter(i => i.json.success === true).length;
}

return [{
  json: {
    processed: inserted + duplicates + failed,
    inserted,
    duplicates,
    failed,
    errors: errors.slice(0, 20)
  }
}];
